25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export type StepResult =
41	  | { premium: number }
42	  | { payout: number; remainingCap: number };
43	
44	export interface ScenarioResult {
45	  results: StepResult[];
46	}
47	
48	const PROCESSING_FEE = 5;
49	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
50	
51	const BASE_PREMIUMS: Record<string, number> = {
52	  sword: 100,
53	  amulet: 60,
54	  staff: 80,
55	};
56	
57	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
58	
59	const quotePremium = (items: Item[]): number => {
60	  const base = items.reduce((sum, item) => sum + basePremiumFor(item), 0);
61	  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE_RATE;
62	  return base + firstInsurance + PROCESSING_FEE;
63	};
64	
65	const runStep = (step: Step): StepResult => {
66	  if (step.op === "quote") {
67	    return { premium: quotePremium(step.items) };
68	  }
69	  return { payout: 0, remainingCap: 0 };
70	};
71	
72	export const runScenario = (scenario: Scenario): ScenarioResult => {
73	  return { results: scenario.steps.map(runStep) };
74	};
